const navbarScrollInit=()=>{var navbar=document.querySelector(".fbs__net-navbar");var scrollTop=window.pageYOffset||document.documentElement.scrollTop;if(navbar){if(scrollTop>0){navbar.classList.add("active")}else{navbar.classList.remove("active")}}};const navbarInit=()=>{document.querySelectorAll('.dropdown-toggle[href="#"]').forEach(function(el,index){el.addEventListener("click",function(event){event.stopPropagation()})})};const logoMarqueeInit=()=>{const wrapper=document.querySelector(".logo-wrapper");const boxes=gsap.utils.toArray(".logo-item");if(boxes.length>0){const loop=horizontalLoop(boxes,{paused:!1,repeat:-1,speed:0.25,reversed:!1,});function horizontalLoop(items,config){items=gsap.utils.toArray(items);config=config||{};let tl=gsap.timeline({repeat:config.repeat,paused:config.paused,defaults:{ease:"none"},onReverseComplete:()=>tl.totalTime(tl.rawTime()+tl.duration()*100),}),length=items.length,startX=items[0].offsetLeft,times=[],widths=[],xPercents=[],curIndex=0,pixelsPerSecond=(config.speed||1)*100,snap=config.snap===!1?(v)=>v:gsap.utils.snap(config.snap||1),totalWidth,curX,distanceToStart,distanceToLoop,item,i;gsap.set(items,{xPercent:(i,el)=>{let w=(widths[i]=parseFloat(gsap.getProperty(el,"width","px")));xPercents[i]=snap((parseFloat(gsap.getProperty(el,"x","px"))/w)*100+gsap.getProperty(el,"xPercent"));return xPercents[i]},});gsap.set(items,{x:0});totalWidth=items[length-1].offsetLeft+(xPercents[length-1]/100)*widths[length-1]-startX+items[length-1].offsetWidth*gsap.getProperty(items[length-1],"scaleX")+(parseFloat(config.paddingRight)||0);for(i=0;i<length;i++){item=items[i];curX=(xPercents[i]/100)*widths[i];distanceToStart=item.offsetLeft+curX-startX;distanceToLoop=distanceToStart+widths[i]*gsap.getProperty(item,"scaleX");tl.to(item,{xPercent:snap(((curX-distanceToLoop)/widths[i])*100),duration:distanceToLoop/pixelsPerSecond,},0).fromTo(item,{xPercent:snap(((curX-distanceToLoop+totalWidth)/widths[i])*100),},{xPercent:xPercents[i],duration:(curX-distanceToLoop+totalWidth-curX)/pixelsPerSecond,immediateRender:!1,},distanceToLoop/pixelsPerSecond).add("label"+i,distanceToStart/pixelsPerSecond);times[i]=distanceToStart/pixelsPerSecond}
function toIndex(index,vars){vars=vars||{};Math.abs(index-curIndex)>length/2&&(index+=index>curIndex?-length:length);let newIndex=gsap.utils.wrap(0,length,index),time=times[newIndex];if(time>tl.time()!==index>curIndex){vars.modifiers={time:gsap.utils.wrap(0,tl.duration())};time+=tl.duration()*(index>curIndex?1:-1)}
curIndex=newIndex;vars.overwrite=!0;return tl.tweenTo(time,vars)}
tl.next=(vars)=>toIndex(curIndex+1,vars);tl.previous=(vars)=>toIndex(curIndex-1,vars);tl.current=()=>curIndex;tl.toIndex=(index,vars)=>toIndex(index,vars);tl.times=times;tl.progress(1,!0).progress(0,!0);if(config.reversed){tl.vars.onReverseComplete();tl.reverse()}
return tl}}};document.addEventListener("DOMContentLoaded",logoMarqueeInit);document.addEventListener("DOMContentLoaded",function(){logoMarqueeInit();navbarInit();window.addEventListener("scroll",navbarScrollInit)});const swiperInit=()=>{var swiper=new Swiper(".testimonialSwiper",{slidesPerView:1,speed:700,spaceBetween:30,loop:!0,pagination:{el:".swiper-pagination",clickable:!0,},breakpoints:{640:{slidesPerView:1.5,spaceBetween:20,},768:{slidesPerView:2.5,spaceBetween:30,},1024:{slidesPerView:2.5,spaceBetween:30,},},navigation:{nextEl:".custom-button-next",prevEl:".custom-button-prev",},});const progressCircle=document.querySelector(".autoplay-progress svg");const progressContent=document.querySelector(".autoplay-progress span");if(progressCircle&&progressContent){var swiper2=new Swiper(".sliderSwiper",{slidesPerView:1,speed:700,spaceBetween:0,loop:!0,centeredSlides:!0,autoplay:{delay:7000,disableOnInteraction:!1},pagination:{el:".swiper-pagination",clickable:!0,},navigation:{nextEl:".custom-button-next",prevEl:".custom-button-prev",},on:{autoplayTimeLeft(s,time,progress){progressCircle.style.setProperty("--progress",1-progress);progressContent.textContent=`${Math.ceil(time / 1000)}s`}}})}};document.addEventListener("DOMContentLoaded",swiperInit);const glightBoxInit=()=>{const lightbox=GLightbox({touchNavigation:!0,loop:!0,autoplayVideos:!0,})};document.addEventListener("DOMContentLoaded",glightBoxInit);const bsOffCanvasInit=()=>{var offcanvasElement=document.getElementById("fbs__net-navbars");if(offcanvasElement){offcanvasElement.addEventListener("show.bs.offcanvas",function(){document.body.classList.add("offcanvas-active")});offcanvasElement.addEventListener("hidden.bs.offcanvas",function(){document.body.classList.remove("offcanvas-active")})}};document.addEventListener("DOMContentLoaded",bsOffCanvasInit);const backToTopInit=()=>{const backToTopContainer=document.getElementById("back-to-top");const backToTopButton=backToTopContainer.querySelector("button");if(backToTopContainer){window.addEventListener("scroll",()=>{if(window.scrollY>170){backToTopContainer.classList.add("show")}else{backToTopContainer.classList.remove("show")}});backToTopButton.addEventListener("click",()=>{window.scrollTo({top:0,behavior:"smooth",})})}};document.addEventListener("DOMContentLoaded",backToTopInit);const inlineSvgInit=()=>{const imgElements=document.querySelectorAll(".js-img-to-inline-svg");if(imgElements){imgElements.forEach((imgElement)=>{const imgURL=imgElement.getAttribute("src");fetch(imgURL).then((response)=>response.text()).then((svgText)=>{const parser=new DOMParser();const svgDocument=parser.parseFromString(svgText,"image/svg+xml");const svgElement=svgDocument.documentElement;Array.from(imgElement.attributes).forEach((attr)=>{if(attr.name!=="class"){svgElement.setAttribute(attr.name,attr.value)}else{const classes=attr.value.split(" ").filter((className)=>className!=="js-img-to-inline-svg");if(classes.length>0){svgElement.setAttribute("class",classes.join(" "))}}});imgElement.replaceWith(svgElement)}).catch((error)=>console.error("Error fetching SVG:",error))})}};document.addEventListener("DOMContentLoaded",inlineSvgInit);const aosInit=()=>{AOS.init({duration:800,easing:'slide',once:!0})}
document.addEventListener("DOMContentLoaded",aosInit);const pureCounterInit=()=>{new PureCounter({selector:".purecounter",})}
document.addEventListener("DOMContentLoaded",pureCounterInit);const addHoverEvents=(dropdown)=>{const dropdownToggle=dropdown.querySelector('.dropdown-toggle');const preventClick=(event)=>event.preventDefault();const showDropdown=()=>{dropdown.classList.add('show');dropdownToggle.setAttribute('aria-expanded','true');const dropdownMenu=dropdown.querySelector('.dropdown-menu');dropdownMenu.classList.add('show')};const hideDropdown=()=>{dropdown.classList.remove('show');dropdownToggle.setAttribute('aria-expanded','false');const dropdownMenu=dropdown.querySelector('.dropdown-menu');dropdownMenu.classList.remove('show')};dropdownToggle.addEventListener('click',preventClick);dropdown.addEventListener('mouseover',showDropdown);dropdown.addEventListener('mouseleave',hideDropdown);dropdown.__events={preventClick,showDropdown,hideDropdown}};const removeHoverEvents=(dropdown)=>{const dropdownToggle=dropdown.querySelector('.dropdown-toggle');const{preventClick,showDropdown,hideDropdown}=dropdown.__events||{};if(preventClick){dropdownToggle.removeEventListener('click',preventClick);dropdown.removeEventListener('mouseover',showDropdown);dropdown.removeEventListener('mouseleave',hideDropdown);delete dropdown.__events}};const handleNavbarEvents=()=>{const dropdowns=document.querySelectorAll('.navbar .dropdown');const dropstarts=document.querySelectorAll('.navbar .dropstart');const dropends=document.querySelectorAll('.navbar .dropend');if(window.innerWidth>=992){dropdowns.forEach(addHoverEvents);dropstarts.forEach(addHoverEvents);dropends.forEach(addHoverEvents)}else{dropdowns.forEach(removeHoverEvents);dropstarts.forEach(removeHoverEvents);dropends.forEach(removeHoverEvents)}};const handleResize=()=>{const dropdowns=document.querySelectorAll('.navbar .dropdown');const dropstarts=document.querySelectorAll('.navbar .dropstart');const dropends=document.querySelectorAll('.navbar .dropend');dropdowns.forEach(removeHoverEvents);dropstarts.forEach(removeHoverEvents);dropends.forEach(removeHoverEvents);handleNavbarEvents()};window.addEventListener('resize',handleResize);handleNavbarEvents();const countdownInit=()=>{const currentYear=new Date().getFullYear();const nextYear=currentYear+1;const launchDate=new Date(`December 31, ${nextYear} 23:59:59`).getTime();const x=setInterval(function(){const now=new Date().getTime();const distance=launchDate-now;const days=Math.floor(distance/(1000*60*60*24));const hours=Math.floor((distance%(1000*60*60*24))/(1000*60*60));const minutes=Math.floor((distance%(1000*60*60))/(1000*60));const seconds=Math.floor((distance%(1000*60))/1000);const daysEl=document.getElementById("days");const hoursEl=document.getElementById("hours");const minutesEl=document.getElementById("minutes");const secondsEl=document.getElementById("seconds");if(daysEl){daysEl.innerText=days}
if(hoursEl){hoursEl.innerText=hours}
if(minutesEl){minutesEl.innerText=minutes}
if(secondsEl){secondsEl.innerText=seconds}
if(distance<0){clearInterval(x);document.querySelector(".countdown").innerText="Launched!"}},1000)};document.addEventListener('DOMContentLoaded',countdownInit)